const getText = (nodeName) => {
  const data = $(nodeName).first().json;
  return String(data?.message?.content ?? data?.message ?? data?.text ?? '').trim();
};
const product = $('Take 1 Only').first().json;
const features = getText('P1: Features & Audience');
const pricing = getText('P2: Pricing');
const reviews = getText('P3: User Reviews');
const compliance = getText('P4: UK Compliance');
const combinedResearch = [
  `PRODUCT: ${product.productName || ''}`,
  `CATEGORY: ${product.category || ''}`,
  `HOMEPAGE: ${product.homepageUrl || 'unknown'}`,
  '',
  '=== FEATURES & AUDIENCE ===', features, '',
  '=== PRICING ===', pricing, '',
  '=== USER REVIEWS ===', reviews, '',
  '=== UK COMPLIANCE ===', compliance,
].join('\n').trim();
return [{ json: {
  id: String(product.id || ''),
  productName: product.productName || '',
  category: product.category || '',
  homepageUrl: product.homepageUrl || '',
  attempts: Number(product.attempts || 0) + 1,
  combinedResearch,
  sectionLengths: { features: features.length, pricing: pricing.length, reviews: reviews.length, compliance: compliance.length, combined: combinedResearch.length }
}}];

const item = $input.first().json;
const errors = [];
const l = item.sectionLengths || {};
if (!item.id) errors.push('Missing product id');
if (!item.productName) errors.push('Missing productName');
if ((l.features || 0) < 120) errors.push(`Features too short (${l.features || 0})`);
if ((l.pricing || 0) < 120) errors.push(`Pricing too short (${l.pricing || 0})`);
if ((l.reviews || 0) < 120) errors.push(`Reviews too short (${l.reviews || 0})`);
if ((l.compliance || 0) < 80) errors.push(`Compliance too short (${l.compliance || 0})`);
if ((l.combined || 0) < 700) errors.push(`Combined too short (${l.combined || 0})`);
return [{ json: { ok: errors.length === 0, errors, ...item } }];

function sanitizeAndParseJson(raw) {
  let str = String(raw || '').replace(/```json\s*/gi, '').replace(/```\s*/gi, '').replace(/\[\d+\]/g, '').trim();
  const start = str.indexOf('{');
  const end = str.lastIndexOf('}');
  if (start === -1 || end === -1 || end <= start) throw new Error('No JSON object found');
  str = str.slice(start, end + 1).replace(/,\s*([}\]])/g, '$1');
  return JSON.parse(str);
}
const inputJson = $input.first().json;
const raw = String(inputJson?.message?.content ?? inputJson?.message ?? inputJson?.text ?? '').trim();
const product = $('Take 1 Only').first().json;
try {
  const review = sanitizeAndParseJson(raw);
  review.id = String(product.id || '');
  review.productName = product.productName || review.productName || '';
  review.category = product.category || review.category || '';
  review.slug = (product.productName || '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
  review.homepageUrl = review.homepageUrl || product.homepageUrl || '';
  review.affiliateLink = review.affiliateLink || review.homepageUrl || product.homepageUrl || '';
  review.dateUpdated = new Date().toISOString().slice(0, 10);
  if (typeof review.score === 'string') review.score = parseFloat(review.score);
  if (Number.isNaN(review.score)) review.score = 0;
  if (typeof review.mtdReady !== 'boolean') review.mtdReady = String(review.mtdReady).toLowerCase() === 'true';
  return [{ json: { parseOk: true, rawWriterSnippet: raw.slice(0, 2000), ...review } }];
} catch (e) {
  return [{ json: { parseOk: false, id: String(product.id || ''), productName: product.productName || '', slug: (product.productName || '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, ''), parseError: e.message, rawWriterSnippet: raw.slice(0, 2000) } }];
}

const item = $input.first().json;
const errors = [];
const wordCount = (s) => String(s || '').trim().split(/\s+/).filter(Boolean).length;
const wc = wordCount(item.detailedReview);
if (!item.id) errors.push('Missing id');
if (!item.productName) errors.push('Missing productName');
if (!item.slug) errors.push('Missing slug');
if (typeof item.score !== 'number' || Number.isNaN(item.score) || item.score < 0 || item.score > 10) errors.push(`Invalid score: ${item.score}`);
if (!item.summary || item.summary.trim().length < 20) errors.push('Summary too short');
if (!item.detailedReview || wc < 350) errors.push(`Detailed review too short (${wc})`);
if (!Array.isArray(item.pros) || item.pros.length < 3) errors.push('Need >=3 pros');
if (!Array.isArray(item.cons) || item.cons.length < 2) errors.push('Need >=2 cons');
if (!Array.isArray(item.pricingTable) || item.pricingTable.length < 1) errors.push('pricingTable missing');
if (!item.homepageUrl || !/^https?:\/\//i.test(item.homepageUrl)) errors.push('Invalid homepageUrl');
if (!item.affiliateLink || !/^https?:\/\//i.test(item.affiliateLink)) errors.push('Invalid affiliateLink');
if (item.verdict && !['YES','NO','MAYBE'].includes(String(item.verdict).toUpperCase())) errors.push('Invalid verdict');
if (item.scoreBreakdown) {
  const keys = ['easeOfUse','valueForMoney','ukFit','supportQuality','featureDepth'];
  for (const k of keys) {
    const n = Number(item.scoreBreakdown[k]);
    if (!Number.isFinite(n) || n < 0 || n > 10) errors.push(`Invalid scoreBreakdown.${k}`);
  }
}
if (item.userQuotes && (!Array.isArray(item.userQuotes) || item.userQuotes.some(q => !q.platform || !q.quote))) errors.push('Invalid userQuotes');
if (item.reviewSignals && (!Array.isArray(item.reviewSignals) || item.reviewSignals.some(s => !s.platform || !s.takeaway))) errors.push('Invalid reviewSignals');
return [{ json: { ok: errors.length === 0, errors, payload: { ...item, wordCount: wc } } }];

